const cheerio = require('cheerio');
const html = $input.first().json.body;
const categoryName = $input.first().json.name || 'Unknown';
const $ = cheerio.load(html);

const productLinks = [];
const seen = new Set();

// Find product links
$('a[href*="/product"], a[href*="/catalog/"]').each((i, el) => {
  let href = $(el).attr('href');
  const text = $(el).text().trim();
  if (!href || !text || text.length < 2) return;
  if (!href.startsWith('http')) href = 'https://www.safcodental.com' + href;
  if (!seen.has(href)) {
    seen.add(href);
    productLinks.push({ url: href, name: text, category: categoryName });
  }
});

// Also try to find product cards
$('[class*="product"] a, .card a').each((i, el) => {
  let href = $(el).attr('href');
  const text = $(el).text().trim();
  if (!href || !text || text.length < 2) return;
  if (!href.startsWith('http')) href = 'https://www.safcodental.com' + href;
  if (!seen.has(href)) {
    seen.add(href);
    productLinks.push({ url: href, name: text, category: categoryName });
  }
});

return productLinks.map(p => ({ json: p }));

const cheerio = require('cheerio');
const item = $input.first().json;
const html = item.body;
const $ = cheerio.load(html);

function trySelectors(selectors) {
  for (const sel of selectors) {
    const el = $(sel).first();
    const text = el.text().trim();
    if (text && text.length > 0) return text;
  }
  return null;
}

function getImages() {
  const imgs = [];
  $('[class*="product"] img, .product-detail img, .gallery img').each((i, el) => {
    let src = $(el).attr('src') || $(el).attr('data-src');
    if (src) {
      if (!src.startsWith('http')) src = 'https://www.safcodental.com' + src;
      if (!imgs.includes(src)) imgs.push(src);
    }
  });
  return imgs;
}

const product = {
  product_name: trySelectors(['h1.product-title', 'h1.product-name', 'h1[class*="product"]', '.product-detail h1', 'h1']),
  brand: trySelectors(['[class*="brand"]', '.product-brand', 'span.brand']),
  sku: trySelectors(['[class*="sku"]', '[class*="item-number"]', '[class*="product-code"]']),
  category: item.category || 'Unknown',
  product_url: item.url,
  price: trySelectors(['[class*="price"]', '.product-price', 'span.price']),
  unit_size: trySelectors(['[class*="unit"]', '[class*="pack-size"]']),
  availability: trySelectors(['[class*="availability"]', '[class*="stock"]']),
  description: trySelectors(['.product-description', '[class*="description"]', '.product-info p']),
  image_urls: getImages(),
  scraped_at: new Date().toISOString(),
  extraction_method: 'css_selectors'
};

// Flag if we got no product name (triggers LLM fallback)
product.needs_llm_fallback = !product.product_name;
product.raw_html = product.needs_llm_fallback ? html.substring(0, 15000) : null;

return [{ json: product }];

const item = $input.first().json;

try {
  let responseText = item.message?.content || item.text || JSON.stringify(item);
  responseText = responseText.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(responseText);

  return [{ json: {
    ...parsed,
    category: item.category || 'Unknown',
    product_url: item.product_url || '',
    scraped_at: new Date().toISOString(),
    extraction_method: 'llm_fallback'
  }}];
} catch(e) {
  return [{ json: {
    product_name: null,
    product_url: item.product_url || '',
    error: 'LLM parsing failed: ' + e.message,
    extraction_method: 'llm_fallback_failed'
  }}];
}

const items = $input.all();
const seen = new Set();
const validated = [];

for (const item of items) {
  const p = item.json;

  // Skip if no product name
  if (!p.product_name || p.product_name.trim() === '') continue;

  // Clean whitespace
  p.product_name = p.product_name.trim();
  if (p.brand) p.brand = p.brand.trim();
  if (p.sku) p.sku = p.sku.trim();
  if (p.price) p.price = p.price.trim();
  if (p.description) p.description = p.description.trim();

  // Deduplicate by name + sku + url
  const key = (p.product_name + '|' + (p.sku || '') + '|' + (p.product_url || '')).toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);

  // Remove internal fields
  delete p.needs_llm_fallback;
  delete p.raw_html;
  delete p.body;
  delete p.error;

  validated.push({ json: p });
}

return validated;
